private val WORDS_SET: Set<String> = (BRACKET_WORDS.values + OPERATOR_WORDS.values).toSet()
fun isBracket(c: Char): Boolean = c in BRACKET_WORDS fun wordFor(c: Char): String? = BRACKET_WORDS[c]
fun toWords(text: String): String = text.map { wordFor(it) ?: it.toString() }.joinToString(" ")
